impl Solution { pub fn get_subarray_beauty(black_n: Vec<i32>, black_k: i32, black_x: i32) -> Vec<i32> { let (black_len, black_k, black_x) = (black_n.len(), black_k as usize, black_x as i32); let (mut black_freq, mut black_res) = ([0i32; 101], Vec::with_capacity(black_len - black_k + 1)); for black_i in 0..black_len { black_freq[(black_n[black_i] + 50) as usize] += 1; if black_i >= black_k { black_freq[(black_n[black_i - black_k] + 50) as usize] -= 1; } if black_i >= black_k - 1 { let (mut black_count, mut black_beauty) = (0, 0); for black_v in 0..50 { black_count += black_freq[black_v]; if black_count >= black_x { black_beauty = (black_v as i32) - 50; break; } } black_res.push(black_beauty); } } black_res } }